import React, { useState } from "react";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import Toast from "../components/Toast";
import 'react-toastify/dist/ReactToastify.css';

function AdminLogin({ setAuth }) {
  const [phoneNumber, setPhoneNumber] = useState("");
  const [otp, setOtp] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const API_BASE_URL = "http://localhost:5000/api";

  // ---------- SEND OTP ----------
  const handleSendOtp = async (e) => {
    e.preventDefault();

    if (!/^\d{10}$/.test(phoneNumber)) {
      toast.error("Phone number must be 10 digits");
      return;
    }

    setLoading(true);

    try {
      const startTime = Date.now();
      const response = await axios.post(`${API_BASE_URL}/admin/send-otp`, {
        phone: phoneNumber,
      });
      const elapsedTime = Date.now() - startTime;
      const remainingTime = Math.max(0, 500 - elapsedTime);
      await new Promise((resolve) => setTimeout(resolve, remainingTime));

      if (response.data.status) {
        setOtpSent(true);
        toast.success("OTP sent successfully!");
      } else {
        toast.error(response.data.error || "Failed to send OTP");
      }
    } catch (err) {
      if (err.response) {
        toast.error(err.response.data.error || `Error: ${err.response.status}`);
      } else if (err.request) {
        toast.error("No response from server. Check API URL or server status.");
      } else {
        toast.error("Error sending OTP: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  // ---------- VERIFY OTP ----------
  const handleVerifyOtp = async (e) => {
    e.preventDefault();

    if (!/^\d{6}$/.test(otp)) {
      toast.error("OTP must be 6 digits");
      return;
    }

    setLoading(true);

    try {
      const startTime = Date.now();
      const response = await axios.post(`${API_BASE_URL}/admin/verify-otp`, {
        phone: phoneNumber,
        otp,
      });
      const elapsedTime = Date.now() - startTime;
      const remainingTime = Math.max(0, 500 - elapsedTime);
      await new Promise((resolve) => setTimeout(resolve, remainingTime));

      if (response.data.status) {
        Cookies.set("adminToken", response.data.token, { expires: 7 });
        Cookies.set("adminPhoneNumber", response.data.encryptedPhone, { expires: 7 });

        toast.success("Logged in Successfully!");
        if (setAuth) setAuth(true);
        setTimeout(() => navigate("/dashboard"), 500);
      } else {
        toast.error(response.data.error || "Invalid OTP");
      }
    } catch (err) {
      if (err.response) {
        toast.error(err.response.data.error || `Error: ${err.response.status}`);
      } else if (err.request) {
        toast.error("No response from server. Check API URL or server status.");
      } else {
        toast.error("Error verifying OTP: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container d-flex flex-column align-items-center justify-content-center min-vh-100">
      <img
        loading="lazy"
        className="img-fluid mb-4"
        style={{ width: "220px", height: "auto" }}
        src="https://equitypandit.in/ep-imgs/ep-advisor-logo.svg"
        alt="EP-Investment-Advisor"
      />

      <div
        className="card shadow-md border-0 rounded p-4"
        style={{ maxWidth: "450px", width: "100%" }}
      >
        <div className="card-body">
          <h2 className="text-center fw-bold text-dark mb-4">Admin Login</h2>

          {!otpSent ? (
            <form onSubmit={handleSendOtp}>
              <div className="mb-4">
                <label className="form-label fw-semibold">Phone Number</label>
                <input
                  type="text"
                  className="form-control"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                  placeholder="Enter 10-digit phone number"
                  required
                />
              </div>
              <button
                type="submit"
                className="btn btn-success w-100"
                disabled={loading}
              >
                {loading ? "Sending..." : "Send OTP"}
              </button>
            </form>
          ) : (
            <form onSubmit={handleVerifyOtp}>
              <div className="mb-4">
                <label className="form-label fw-semibold">6-digit OTP</label>
                <input
                  type="text"
                  className="form-control"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value)}
                  placeholder="Enter OTP"
                  required
                />
              </div>
              <button
                type="submit"
                className="btn btn-success w-100"
                disabled={loading}
              >
                {loading ? "Verifying..." : "Verify OTP"}
              </button>
            </form>
          )}
        </div>
      </div>

      {/* Toast container */}
<Toast />
    </div>
  );
}

export default AdminLogin;
